const data = $json;

const cleanText = (arr) => {
  if (!arr) return '';
  return Array.isArray(arr)
    ? arr.join(' ').replace(/\s+/g, ' ').trim()
    : arr;
};

return [{
  json: {
    ...data,
    clean_content: [
      cleanText(data.title),
      cleanText(data.meta_description),
      cleanText(data.headings),
      cleanText(data.paragraphs)
    ].join(' ').slice(0, 5000) // prevent token explosion
  }
}];

const raw = $input.first().json;

// ✅ SAFE reference to previous node item
const job = $item(0).$node["🌐 AI Domain Found?"].json;

// ✅ Current node data
const website_body = $json.clean_content || '';

let classification = 'EMPLOYER';
let industry = 'Other';
let reason = '';

try {
  const content = raw.output?.[0]?.content?.[0]?.text;

  if (content && typeof content === 'object') {
    classification = content.classification || 'EMPLOYER';
    industry = content.industry || 'Other';
    reason = content.reason || '';
  }

} catch (e) {
  reason = 'parse_error';
}

return [{
  json: {
    ...job,
    company_site_body: website_body,
    company_type: classification,
    industry: industry, // ✅ NEW FIELD
    classification_reason: reason
  }
}];

const job = $json;

// Parse original_json safely
let parsed = {};
try {
  parsed = typeof job.original_json === 'string'
    ? JSON.parse(job.original_json)
    : job.original_json || {};
} catch (e) {
  parsed = {};
}

// Extract emails from original_json
let emails = Array.isArray(parsed.emails) ? parsed.emails : [];

// Generic email providers to skip
const genericDomains = new Set([
  'gmail.com','yahoo.com','hotmail.com','outlook.com','live.com',
  'aol.com','icloud.com','mail.com','protonmail.com','zoho.com',
  'yandex.com','gmx.com','inbox.com','fastmail.com',
  'yahoo.co.uk','hotmail.co.uk','outlook.co.uk',
  'yahoo.in','rediffmail.com','msn.com','me.com',
  'googlemail.com','yahoo.co.in','outlook.in'
]);

let domain = '';

for (const email of emails) {
  if (!email || typeof email !== 'string' || !email.includes('@')) continue;

  const emailDomain = email.split('@')[1]?.toLowerCase().trim();

  if (
    emailDomain &&
    !genericDomains.has(emailDomain) &&
    emailDomain.includes('.')
  ) {
    domain = emailDomain;
    break;
  }
}

return {
  json: {
    ...job,
    email_found: emails.length > 0,
    company_website: domain,
    domain_source: domain ? 'email_extraction' : ''
  }
};

const raw = $input.first().json;
const job = $('🌐 Has Domain?').item.json;

let domain = '';
let linkedin_url = '';
let domainSource = '';

// ✅ Extract domain
if (raw.official_website) {
  domain = raw.official_website
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .split('/')[0]
    .trim();
}

// ✅ Extract LinkedIn
if (Array.isArray(raw.social_links)) {
  const linkedin = raw.social_links.find(link =>
    link.includes('linkedin.com/company')
  );

  if (linkedin) {
    linkedin_url = linkedin;
  }
}

// 🚫 Filter invalid domains
const invalidDomains = ['linkedin', 'indeed', 'glassdoor', 'google'];

if (
  !domain ||
  invalidDomains.some(d => domain.includes(d))
) {
  domain = '';
  domainSource = 'invalid';
} else {
  domainSource = 'apify';
}

return [{
  json: {
    ...job,
    company_website: domain,
    company_linkedin: linkedin_url,
    domain_source: domainSource
  }
}];

