const raw = $input.first().json;
const job = $('🔄 Loop: Each Job2').item.json;
const company = $("💾 Save Domain to Sheet2").item.json;
let contacts = [];
let strategy = '';

function safeParse(input) {
  try {
    // Case 1: Already parsed JSON
    if (typeof input === 'object' && input !== null) {

      // ✅ HANDLE YOUR CURRENT STRUCTURE
      if (input.message?.content) {
        const content = input.message.content;

        // If content is already an object → use directly
        if (typeof content === 'object') {
          return content;
        }

        // If content is string → clean + parse
        if (typeof content === 'string') {
          const cleaned = content.replace(/```json\n?|```/g, '').trim();
          return JSON.parse(cleaned);
        }
      }

      // Fallback (other AI formats)
      if (input.output?.[0]?.content?.[0]?.text) {
        return JSON.parse(input.output[0].content[0].text);
      }

      return input;
    }

    // Case 2: Raw string
    if (typeof input === 'string') {
      return JSON.parse(input);
    }

    return null;

  } catch (err) {
    return null;
  }
}

const parsed = safeParse(raw);
total_contacts_found: contacts.length;
// ✅ Extract safely
if (parsed && Array.isArray(parsed.selected_contacts)) {
  contacts = parsed.selected_contacts;
  strategy = parsed.strategy || '';
} else {
  contacts = [];
  strategy = parsed?.strategy || 'Parse error or invalid structure';
}

// ✅ No contacts fallback
if (contacts.length === 0) {
  return [{
    json: {
      ...job,
      no_contacts_found: true,
      strategy
    }
  }];
}

// ✅ Map ALL contacts (1, 2, 3... scalable)
return contacts.map(contact => ({
  json: {
    ...job,
    ...company,
    total_contacts_found: contacts.length,
    contact_name: contact.name || '',
    contact_role: contact.role || '',
    contact_email: contact.email || '',
    contact_linkedin: contact.linkedinUrl || '',
    location_match: contact.location_match ?? false,
    needs_enrichment: contact.needs_enrichment ?? !contact.email,
    contact_priority: contact.priority || 'medium',
    selection_reason: contact.reason || '',
    strategy
  }
}));

const response = $input.first().json;
const contact = $('📧 Has Email?').item.json;

// LinkedIn scraper returns array, get first result
let profile = Array.isArray(response) ? response[0] : response;

// Extract email from profile
let email = '';
if (profile) {
  // Check various email fields
  if (profile.email) {
    email = profile.email;
  } else if (profile.emails && profile.emails.length > 0) {
    email = profile.emails[0];
  } else if (profile.contactInfo?.email) {
    email = profile.contactInfo.email;
  }
}

return [{
  json: {
    ...contact,
    contact_email: email,
    contact_name: profile?.fullName || profile?.firstName + ' ' + profile?.lastName || contact.contact_name,
    contact_role: profile?.headline || contact.contact_role,
    enrichment_source: 'linkedin_scraper',
    linkedin_enriched: true
  }
}];

const items = $input.all();
const job = $('🌐 Has Domain?2').item.json;

const results = items.map(item => {
  const profile = item.json;

  // ✅ Name
  const name = `${profile.firstName || ''} ${profile.lastName || ''}`.trim();

  // ✅ Job title (from experience or headline fallback)
  let job_title = '';
  if (Array.isArray(profile.experience) && profile.experience.length > 0) {
    job_title = profile.experience[0].position || '';
  }

  // fallback
  if (!job_title) {
    job_title = profile.headline || '';
  }

  // ✅ Email (safe extraction)
  let email = '';
  if (Array.isArray(profile.emails) && profile.emails.length > 0) {
    email = profile.emails[0].email || '';
  }

  // ✅ Company LinkedIn
  let companyLinkedin = '';
  if (profile.currentPosition?.[0]?.companyLinkedinUrl) {
    companyLinkedin = profile.currentPosition[0].companyLinkedinUrl;
  }

  // ✅ Location
  const location = profile.location?.linkedinText || '';

  return {
    company: job.company_name || '',
    name,
    job_title,
    job_headline: profile.headline || '',
    email,
    linkedinUrl: profile.linkedinUrl || '',
    companyLinkedin,
    location
  };
});

return [{
  json: {
    contacts: results
  }
}];

const job = $('🔄 Loop: Each Job2').item.json;
const company = $("💾 Save Domain to Sheet2").item.json;
const domain_extraction = $("📝 Parse Classification").item.json;

return [{
  json: {
    ...job,
    ...company,
    ...domain_extraction
  }
}];
